INSERT INTO public.photos VALUES (23064, 'Plaza de las Canteras 1991', 'Imagen capturada durante las obras de remodelaciâ”śâ”‚n de la plaza de las Canteras que, realizada para aumentar la superficie peatonal, limitar la circulatoria a un solo sentido, y la supresiâ”śâ”‚n de la zona de aparcamiento, incluyâ”śâ”‚ ademâ”śĂ­s un conjunto monumental en memoria del maestro Manuel de Villanueva ampliado con una escultura que homenajea a la profesiâ”śâ”‚n de cantero. En la imagen, la estructura del muro que formaba parte del conjunto ya era objeto de una campaâ”śâ–’a de oposiciâ”śâ”‚n por vecinos del entorno, como indica la pancarta que pende detrâ”śĂ­s, sobre el arranque de la calle de Alicante. En la versiâ”śâ”‚n definitiva de este muro se rebajarâ”śÂˇa en altura la zona mâ”śĂ­s inmediata al paso de peatones de la derecha.', 1991, 1991, 1991, 'Anos 90', 'TORRERO', 41.63158600, -0.88626600, '0101000020E6100000C8D0B1834A5CECBF444E5FCFD7D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50510973582.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50510973582.webp', 'https://www.flickr.com/photos/zaragozaantigua/50510973582/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23357, 'Canal Imperial 1934', 'â”¬Â˝Revistiâ”śâ”‚ gran brillantez el homenaje a Pignatelli celebrado el domingoâ”¬â•—, El Noticiero (Zaragoza, 16-X-1934, p. 5). El 14 de octubre tuvo lugar una gran fiesta nâ”śĂ­utica en la Playa de Torrero. Surcaron las aguas 9 barcazas decoradas con sâ”śÂˇmbolos agrâ”śÂˇcolas, barrios de la ciudad y de pueblos ribereâ”śâ–’os del Canal, como "Alagâ”śâ”‚n", "Bajo Aragâ”śâ”‚n", "Rabal", "Lumpiaque"... Mâ”śâ•‘sica, rondallas, jotas, flores, dos aeroplanos volando por los cielos... Y todo dentro del programa de actos festivos en homenaje al gran impulsor de la obra del Canal Imperial, en el aniversario 200 de su natalicio. Otro acto fue el proyecto de realizaciâ”śâ”‚n de un monumento en su honor en el Hogar del mismo nombre, cuya primera y â”śâ•‘nica piedra se colocâ”śâ”‚ en estas fechas. Fuente visual: archivo Heraldo de Aragâ”śâ”‚n, en "Padre Ebro. El râ”śÂˇo Ebro y el siglo XX".', 1934, 1934, 1934, 'Anos 30', 'TORRERO', 41.63341800, -0.88673100, '0101000020E6100000172EABB01960ECBF4F594DD713D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15060741460.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15060741460.webp', 'https://www.flickr.com/photos/zaragozaantigua/15060741460/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23359, 'Pasarela del Canal 1934', 'El 14 de octubre de 1934 tuvo lugar una gran fiesta nâ”śĂ­utica en el Canal Imperial, dentro de un festivo programa de actos en homenaje a Ramâ”śâ”‚n Pignatelli, en el aniversario 200 de su natalicio. En la imagen, aspecto del Canal Imperial desde la pasarela peatonal de la calle Ruiz Tapiador, desmontada dâ”śÂ®cadas despuâ”śÂ®s para poner un paso para los coches. Al fondo, a la derecha, el embarcadero. Mâ”śĂ­s al fondo, el Puente de Amâ”śÂ®rica. Fuente visual: www.facebook.com/photo.php?fbid=953416374686481&set=g...', 1934, 1934, 1934, 'Anos 30', 'TORRERO', 41.63362300, -0.88773600, '0101000020E61000005D6BEF535568ECBF287FF78E1AD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15138070513.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15138070513.webp', 'https://www.flickr.com/photos/zaragozaantigua/15138070513/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23373, 'Puente de Amâ”śÂ®rica 1833', '"El puente de Amâ”śÂ®rica", litografâ”śÂˇa de Faramundo Blanchard. Puente de Amâ”śÂ®rica del Canal Imperial. A la derecha, la dâ”śĂ­rsena. Fuente visual: "Memoria histâ”śâ”‚rica del Canal imperial de Aragon: noticia sobre las utilidades que produce, y esplicacion de lo que contienen las lâ”śĂ­minas que se publican", Madrid, 1833.', 1833, 1833, 1833, 'Siglo XIX', 'TORRERO', 41.63307000, -0.88480700, '0101000020E61000002DB308C55650ECBF130A117008D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20162787040.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20162787040.webp', 'https://www.flickr.com/photos/zaragozaantigua/20162787040/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23379, 'Puente de Amâ”śÂ®rica 1933', 'Puente de Amâ”śÂ®rica, Canal Imperial de Aragâ”śâ”‚n, draga, y Torre de Pina, al fondo. Fuente visual: Foto Conrado Barlâ”śÂ®s, donada por Daniel Barlâ”śÂ®s y digitalizada por Josâ”śÂ® Luis Cintora para www.rafaelcastillejo.com', 1933, 1933, 1933, 'Anos 30', 'TORRERO', 41.63329300, -0.88504400, '0101000020E61000003BAC70CB4752ECBF93E4B9BE0FD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22614681504.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22614681504.webp', 'https://www.flickr.com/photos/zaragozaantigua/22614681504/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23381, 'Canal Imperial 1933', 'Canal Imperial desde la metâ”śĂ­lica pasarela de Venecia. Al fondo, el embarcadero, el Puente de Amâ”śÂ®rica y la Torre de Pina. A la derecha, barcazas de transporte de ladrillos. Fuente visual: Foto Conrado Barlâ”śÂ®s, donada por Daniel Barlâ”śÂ®s y digitalizada por Josâ”śÂ® Luis Cintora para www.rafaelcastillejo.com', 1933, 1933, 1933, 'Anos 30', 'TORRERO', 41.63347700, -0.88694300, '0101000020E6100000EC504D49D661ECBF54E23AC615D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22947139610.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22947139610.webp', 'https://www.flickr.com/photos/zaragozaantigua/22947139610/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23392, 'Canal Imperial c.1933', 'Imagen del Canal Imperial capturada desde la metâ”śĂ­lica pasarela que conducâ”śÂˇa, hacia la derecha, a la calle de Ruiz Tapiador de la barriada de Venecia. Hacia el fondo, el embarcadero, el Puente de Amâ”śÂ®rica y la Torre de Pina. A la izquierda, el frecuentado paseo del Canal y el tramo despejado de edificios entre Villa Rosario y la almenara de Santa Engracia y la nueva acequia del Plano. A la derecha, grandes barcazas de transporte de ladrillos, y en la orilla, montones de ellos apilados. Las barcas recreativas rememoran que el Canal Imperial, lejos de constituirse en trinchera o frontera, fue concebido tambiâ”śÂ®n como una eficiente vâ”śÂˇa de comunicaciâ”śâ”‚n mediante la navegaciâ”śâ”‚n que, a diferencia del principal de los râ”śÂˇos de la ciudad, conllevaba un dragado regular. Fuente visual: postal editada y comercializada por la Editorial Arribas.', 1933, 1933, 1933, 'Anos 30', 'TORRERO', 41.63347700, -0.88694300, '0101000020E6100000EC504D49D661ECBF54E23AC615D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36593606222.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36593606222.webp', 'https://www.flickr.com/photos/zaragozaantigua/36593606222/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23395, 'P.â”¬â•‘ del Canal c.1926', 'Invernal imagen capturada en el paseo del Canal y centrada en la pasarela peatonal que enlazaba con la calle de Venecia, y que habâ”śÂˇa sido construida con un alto gâ”śĂ­libo para favorecer la navegaciâ”śâ”‚n canalina. En la pasarela destaca el tremendo comercial de los Almacenes de calzado de Antonio Mas, sitos en la calle de Don Jaime I nâ”¬â•‘ 54, junto al Hotel Universo y Cuatro Naciones de Pedro Durio. A la izquierda, despejada vista de la Vâ”śÂˇa de Pignatelli, con imagen posiblemente de las traseras del inmueble unifamiliar del nâ”¬â•‘ 7 de la calle de Royo. Hacia el fondo y tras la pasarela, el embarcadero recreativo inmediato al puente de Amâ”śÂ®rica, y mâ”śĂ­s al fondo, en la curva del Canal Imperial de Aragâ”śâ”‚n hacia el cabezo Cortado, la gran casa de Dâ”śĂ­maso Pina.', 1926, 1926, 1926, 'Anos 20', 'TORRERO', 41.63350300, -0.88856200, '0101000020E6100000BDFC4E93196FECBF7D7555A016D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48520811962.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48520811962.webp', 'https://www.flickr.com/photos/zaragozaantigua/48520811962/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23397, 'Canal Imperial de Aragâ”śâ”‚n 1996', 'Imagen centrada en uno de los antiguos quioscos que flanqueaban el ingreso al puente de Amâ”śÂ®rica desde el paseo de Cuâ”śÂ®llar, habilitado como oficina de informaciâ”śâ”‚n de Disminuidos Fâ”śÂˇsicos de Aragâ”śâ”‚n. Al fondo y a la derecha destaca la torre del Sacrario Militare Italiano. La situaciâ”śâ”‚n de abandono de estas instalaciones, asâ”śÂˇ como de las riberas del Canal Imperial de Aragâ”śâ”‚n, eran denunciadas de forma regular por vecinos y representantes institucionales, sin demasiado â”śÂ®xito.', 1996, 1996, 1996, 'Anos 90', 'TORRERO', 41.63351100, -0.88525700, '0101000020E610000026C3F17C0654ECBF005471E316D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50510452268.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50510452268.webp', 'https://www.flickr.com/photos/zaragozaantigua/50510452268/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23494, 'P.â”¬â•‘ de Colâ”śâ”‚n 1947', 'Imagen capturada en el paseo de Colâ”śâ”‚n del que fuera hotel de Basilio Palomar Labal reformado y ampliado por el arquitecto Josâ”śÂ® Yarza Garcâ”śÂˇa para adaptarlo como clâ”śÂˇnica operatoria del doctor Francisco Seral Casas (mâ”śÂ®dico-cirujano del Hospital de la Cruz Roja), con el aspecto que tenâ”śÂˇa el dâ”śÂˇa de su bendiciâ”śâ”‚n e inauguraciâ”śâ”‚n bajo el nombre de "Clâ”śÂˇnica de San Francisco", con capacidad de veinte camas. La ceremonia de bendiciâ”śâ”‚n corriâ”śâ”‚ a cargo de Hernâ”śĂ­n Cortâ”śÂ®s Pastor, vicario general de la archidiâ”śâ”‚cesis y deâ”śĂ­n del Cabildo Metropolitano, y al acto asistiâ”śâ”‚ numerosa y selecta representaciâ”śâ”‚n de la Zaragoza de la â”śÂ®poca, que fue obsequiada con una copa de vino espaâ”śâ–’ol.', 1947, 1947, 1947, 'Anos 40', 'TORRERO', 41.63376700, -0.88584700, '0101000020E6100000904FC8CEDB58ECBF5B24ED461FD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54218918367.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54218918367.webp', 'https://www.flickr.com/photos/zaragozaantigua/54218918367/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24230, 'Canal Imperial 1947', 'Las fiestas mayores de octubre de ese aâ”śâ–’o estuvieron trufadas, no podâ”śÂˇa ser de otra forma, de hispanidad y advenimiento, y ungidas de fe y patriâ”śâ”‚tico estâ”śÂˇmulo, aunque parece que, en tâ”śÂ®rminos prâ”śĂ­cticos, una modesta "cabalgata" fluvial organizada en el Canal Imperial se convirtiâ”śâ”‚ en el evento mâ”śĂ­s destacado del espartano programa fiestero. Aâ”śâ•‘n no se habâ”śÂˇan inventado la ofrenda floral-frutâ”śÂˇcola de aâ”śâ–’os despuâ”śÂ®s. Esta "cabalgata" consistiâ”śâ”‚ en un descenso, desde el chalet de Buenavista, y hasta el Puente de Amâ”śÂ®rica, de varios pontones sobre los que se emplazaron reproducciones en bulto redondo de elementos del pasado de la ciudad, como la estatua de Pignatelli, la Fuente de los Incrâ”śÂ®dulos, y la Puerta del Carmen, modeladas por el escultor local Armando Ruiz Lorda con materiales efâ”śÂˇmeros. En otro pontâ”śâ”‚n, un cuadro de jota representaba en directo un homenaje a la jota. Mucha gente se congregâ”śâ”‚ para seguir en vivo a esta oficial bajada del Canal, con un tiempo mâ”śĂ­s bien fresco. Unos dâ”śÂˇas antes, el Canal habâ”śÂˇa sido escenario de una no menos fresca "travesâ”śÂˇa" a nado, pero a lo largo, durante 2500 metros, y de una carrera de piraguas sobre esa misma distancia. En la imagen, tramo del Canal entre la pasarela de la calle Ruiz Tapiador (a la izquierda, fuera de plano), y el puente de Amâ”śÂ®rica, con el ilustrado pontâ”śâ”‚n de las reproducciones de la estatua de Ramâ”śâ”‚n Pignatelli, y la Fuente que dedicâ”śâ”‚ amablemente a los zaragozanos incrâ”śÂ®dulos del Canal. Conducen el artefacto, soldados del ramo pontonero. Fuente visual: Gerardo Sancho Ramo, Archivo Municipal de Zaragoza.', 1947, 1947, 1947, 'Anos 40', 'TORRERO', 41.63347700, -0.88694300, '0101000020E6100000EC504D49D661ECBF54E23AC615D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27649259434.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27649259434.webp', 'https://www.flickr.com/photos/zaragozaantigua/27649259434/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24254, 'â”śĂĽngel Cortâ”śÂ®s Gracia 1936', 'Imagen de â”śĂĽngel Cortâ”śÂ®s Gracia, alias Skogler, con indumentaria falangista de campaâ”śâ–’a en las inmediaciones del cuartel de Castillejos o Torrero, donde terminaba la avenida del Siglo XX. Al fondo, poste de suministro elâ”śÂ®ctrico de los tranvâ”śÂˇas de las lâ”śÂˇneas 5. Torrero y 8. Cementerio, y el paseo del Canal. Antiguo operario del estudio fotogrâ”śĂ­fico de Carlos Skogler Fredikson, â”śĂĽngel Cortâ”śÂ®s Gracia mantuvo bajo la denominaciâ”śâ”‚n Foto Skogler una mâ”śĂ­s que interesante actividad profesional que, gracias a su pionera militancia en Falange Espaâ”śâ–’ola, desde el triunfo de la rebeliâ”śâ”‚n armada contra la Repâ”śâ•‘blica en julio de 1936 le convirtiâ”śâ”‚ en privilegiado notario de la Zaragoza de la â”śÂ®poca.', 1936, 1936, 1936, 'Anos 30', 'TORRERO', 41.63385600, -0.88494600, '0101000020E6100000863B17467A51ECBFCB2F833122D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51367473994.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51367473994.webp', 'https://www.flickr.com/photos/zaragozaantigua/51367473994/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24469, 'Fâ”śĂ­brica Larraz 1945', 'Dibujo de la fâ”śĂ­brica de gâ”śÂ®neros de punto Viuda de Rudesindo Larraz, en los nâ”śâ•‘meros 1 al 5 de la calle de Ruiz Tapiador, junto al Canal Imperial (a la izquierda, fuera del encuadre).', 1945, 1945, 1945, 'Anos 40', 'TORRERO', 41.63332500, -0.88845500, '0101000020E61000003CF71E2E396EECBF9E5E29CB10D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20141251123.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20141251123.webp', 'https://www.flickr.com/photos/zaragozaantigua/20141251123/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25036, 'Sacrario Militare 1942', 'Imagen capturada durante la ceremonia de colocaciâ”śâ”‚n y bendiciâ”śâ”‚n de la primera piedra del mausoleo dedicado a los legionarios italianos muertos durante su intervenciâ”śâ”‚n en la guerra de Espaâ”śâ–’a 1936-39, apoyando a los nacionalistas. Ya en febrero de ese aâ”śâ–’o se habâ”śÂˇa bendecido la primera piedra de la nueva iglesia de los capuchinos, y en mayo tuvo lugar la del Sacrario Militare, con el esplendor propio de la tradiciâ”śâ”‚n "imperial y romana" del râ”śÂ®gimen fascista italiano. El entorno habâ”śÂˇa sido adornado con abundante banderâ”śÂˇa italoespaâ”śâ–’ola, un piquete de "carabineri", una compaâ”śâ–’â”śÂˇa del ejâ”śÂ®rcito espaâ”śâ–’ol, un altar presidido por imagen de San Antonio de Padua, y la maqueta del proyecto. El Nuncio de Su Santidad estaba acompaâ”śâ–’ado por las mâ”śĂ­s altas autoridades militares, religiosas, e institucionales de la ciudad y provincia, ademâ”śĂ­s de numerosa presencia de jerarcas del Râ”śÂ®gimen, y de la Orden de los capuchinos. A la santa misa le siguiâ”śâ”‚ la bendiciâ”śâ”‚n de la primera piedra, y la colocaciâ”śâ”‚n de la misma, junto con un pergamino que literalmente rezaba "Reinando Vâ”śÂˇctor Manuel III, mientras Roma pugna contra los enemigos del derecho y de la fe, bajo los auspicios de Mussolini y Franco, con la bendiciâ”śâ”‚n del Romano Pontâ”śÂˇfice Pâ”śÂˇo XII, esta obra de paz, a la costumbre de los Padres, para el incremento de la religiâ”śâ”‚n y la memoria de los legionarios italianos caâ”śÂˇdos en Espaâ”śâ–’a, se levanta con romana grandeza el dâ”śÂˇa 3 de mayo de 1942". Fuente visual: Los Capuchinos en Zaragoza, IV centenario (1598-1998).', 1942, 1942, 1942, 'Anos 40', 'TORRERO', 41.63469100, -0.88530900, '0101000020E6100000C5573B8A7354ECBF6308008E3DD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32024226495.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32024226495.webp', 'https://www.flickr.com/photos/zaragozaantigua/32024226495/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25739, 'Iglesia de San Antonio 1988', 'Foto Eduardo Zamarripa, 1988. Vista aâ”śÂ®rea de la iglesia de San Antonio. Fuente: Aragâ”śâ”‚n desde el aire, Ministerio de Defensa, 1988.', 1988, 1988, 1988, 'Anos 80', 'TORRERO', 41.63469100, -0.88530900, '0101000020E6100000C5573B8A7354ECBF6308008E3DD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20319654525.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20319654525.webp', 'https://www.flickr.com/photos/zaragozaantigua/20319654525/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25943, 'Puente de Amâ”śÂ®rica 1976', 'Nada mâ”śĂ­s cruzar el Puente de Amâ”śÂ®rica, y a la derecha, la actual Vâ”śÂˇa Ramâ”śâ”‚n Pignatelli es una denominaciâ”śâ”‚n bastante reciente para una calle que no ha tenido nombre durante muchas mâ”śĂ­s dâ”śÂ®cadas. Era una calle del barrio de Venecia junto al Canal, y eso era suficiente, bastante antes de que a alguien se le ocurriera lo de utilizar "Venecia" como comodâ”śÂˇn de expansiâ”śâ”‚n urbanâ”śÂˇstica hasta la Plana de Zaragoza. En la imagen, captura del Puente de Amâ”śÂ®rica desde la Playa de Torrero, sita en el barrio de S. Josâ”śÂ®. El edificio de viviendas que hace esquina es una exquisita supervivencia de comienzos del siglo XX (1904), y hace el nâ”¬â•‘ 1 de la calle, entonces con publicidad de la academia "Tuga". El nâ”¬â•‘ 3, ya es de 1960, sobre unos anteriores corrales. En la foto aâ”śâ•‘n estaban en pie las parcelas de los viejos nâ”śâ•‘meros 2 y 3, que junto con sus traseros huertos serâ”śĂ­n demolidas, y sobre ellas construidos los nuevos nâ”¬â•‘ 5 (1977) y nâ”¬â•‘ 7 (1978). El enorme bloque de los nâ”śâ•‘meros 11 y 13 ya estaba en pie desde 1969. A esa altura, aproximadamente, estaba situado el embarcadero del Canal que aparece recogido en bastantes fotos de principios de siglo XX. Fue tambiâ”śÂ®n derruido, y en su lugar se ha puesto un monolito que lo recuerda, y que nadie lee, porque hay que pasar por allâ”śÂˇ para enterarte de que estâ”śĂ­. Como no estâ”śĂ­ relacionado con Los Sitios, pues nada. Mâ”śĂ­s hacia la derecha, las sombras de los altos bloques de viviendas de los nâ”śâ•‘meros 21 (1962), 25 (1963), 29 (1966), y 33 (1962) de la misma calle Vâ”śÂˇa Ramâ”śâ”‚n Pignatelli. En primer plano, prâ”śĂ­ctica de la pesca que se mantiene en el tiempo, a la busca de carpas y alburnos, y algâ”śâ•‘n ocasional pez fraile. Lo nuevo son las anâ”śĂ­tidas, palomas, cotorras. Fuente visual: AVV. San Josâ”śÂ®.', 1976, 1976, 1976, 'Anos 70', 'TORRERO', 41.63321400, -0.88494600, '0101000020E6100000863B17467A51ECBF47AF06280DD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19631973063.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19631973063.webp', 'https://www.flickr.com/photos/zaragozaantigua/19631973063/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25945, 'Puente de Amâ”śÂ®rica 1979', 'Puente de Amâ”śÂ®rica despojado de esa imagen româ”śĂ­ntica asociada al Canal Imperial navegable. La antigua gran dâ”śĂ­rsena ha sido sustituida por funcionalistas oficinas de la administraciâ”śâ”‚n del Canal. Erradicado el tranvâ”śÂˇa, quedan las vâ”śÂˇas y parte del adoquinado, que se van difuminando con cada parcheo del vial. El puente, sometido al vasallaje del trafico rodado. A la derecha, en un cartel de las las elecciones generales del 1 de marzo de ese aâ”śâ–’o, Felipe Gonzâ”śĂ­lez anuncia "Un Gobierno firme para vencer el paro". Fuente visual: AVV. San Josâ”śÂ®', 1979, 1979, 1979, 'Anos 70', 'TORRERO', 41.63307000, -0.88480700, '0101000020E61000002DB308C55650ECBF130A117008D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20352048936.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20352048936.webp', 'https://www.flickr.com/photos/zaragozaantigua/20352048936/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25951, 'Puente de Amâ”śÂ®rica 1975', 'Imagen capturada desde el Sacrario Militare Italiano, con panorâ”śĂ­mica del puente de Amâ”śÂ®rica y sus entraâ”śâ–’ables quioscos, el Canal Imperial y las modernas instalaciones de la CHE, y algunos de los nuevos bloques de viviendas de los barrios de Torrero y la Paz. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1975, 1975, 1975, 'Anos 70', 'TORRERO', 41.63326100, -0.88474300, '0101000020E61000007DAD4B8DD04FECBF876A4AB20ED14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30179240966.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30179240966.webp', 'https://www.flickr.com/photos/zaragozaantigua/30179240966/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20869, 'El Barranco de la Muerte 1118', 'El Barranco de la Muerte. Agustâ”śÂˇn Salinas, 1892. Palacio de Sâ”śĂ­stago, Diputaciâ”śâ”‚n de Zaragoza. Segâ”śâ•‘n la leyenda, Alfonso I el Batallador (en el centro de la imagen) hizo que el ejâ”śÂ®rcito de los musulmanes que habitaban Saraqusta se congregara en el Barranco de la Muerte, supuestamente llamado asâ”śÂˇ desde que ocurriâ”śâ”‚ este episodio bâ”śÂ®lico en 1118. Serâ”śÂˇa uno de los episodios mâ”śĂ­s sangrientos de la campaâ”śâ–’a de asedios que terminâ”śâ”‚ con la conquista cristiana de la ciudad. En primer plano, unos cuantos muertos del bando musulmâ”śĂ­n, que acudiâ”śâ”‚ engaâ”śâ–’ado al lugar y fue exterminado en el fondo del barranco por los soldados cristianos que esperaban agazapados, segâ”śâ•‘n cuenta el ancestral relato. Al fondo a la izquierda, Saraqusta humeante. El barranco en cuestiâ”śâ”‚n se halla al sur de la ciudad, en los montes de Torrero, entre el cementerio y el Canal Imperial.', 1118, 1118, 1118, 'Siglo XIX', 'TORRERO', 41.62021300, -0.87905100, '0101000020E6100000DC8310902F21ECBFEBC6BB2363CF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14814731538.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14814731538.webp', 'https://www.flickr.com/photos/zaragozaantigua/14814731538/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24934, 'Puente Trece de Septiembre 1928', 'Proyectado por Miguel â”śĂĽngel Navarro sobre el râ”śÂˇo Huerva, a la entrada del Parque de Buenavista, comenzaron las obras en marzo de 1928, siendo inaugurado en junio por el dictador Primo de Rivera. Se considera una construcciâ”śâ”‚n singular dentro de la estâ”śÂ®tica de la â”śÂ®poca, con tendencias eclâ”śÂ®cticas e historicistas. La obra fue acometida por la empresa â”śĂĽngel Aisa y Hermano. En homenaje al dictador fue bautizado como Puente del Trece de septiembre sobre el râ”śÂˇo Huerva, por la fecha del Golpe de Estado realizado en 1923 con el consentimiento y respaldo del rey Alfonso XIII. Con la llegada de la democracia republicana, el puente fue redenominado del Catorce de Julio. Tras el golpe de 1936 fue redenominado del Trece de Septiembre. En 1991 se le redenominâ”śâ”‚ Puente del Parque, y en 2012 como Puente de los Cantautores. Fuente visual: Zaragoza, dos milenios de agua.', 1928, 1928, 1928, 'Anos 20', 'UNIVERSIDAD', 41.63730400, -0.89775100, '0101000020E610000004711E4E60BAECBF14CE6E2D93D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15366774293.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15366774293.webp', 'https://www.flickr.com/photos/zaragozaantigua/15366774293/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21355, 'Vista desde el Canal 1900', 'Imagen capturada desde el campo de cereal propiedad de Alejandro Palomar de la Torre e inmediato en cota superior al Canal Imperial de Aragâ”śâ”‚n en la gran curva previa al Cabezo Cortado. En la margen izquierda del Canal discurre el terroso camino de la Quinta Julieta que conduce a esa torre recreativa de Enrique Sagols Ferrer. A continuaciâ”śâ”‚n, baldâ”śÂˇos y desniveles hacia el barrio de Colâ”śâ”‚n a la izquierda y al de Cuber en el centro, donde destaca la Torre de Cuber y su fâ”śĂ­brica de aprestos, ademâ”śĂ­s de la fâ”śĂ­brica de tejas de Constantin en el espacio entre la acequia del Plano y el camino del Puente del Virrey. Algo mâ”śĂ­s hacia la derecha y hacia el fondo emerge la gran estructura del Asilo de las Hermanitas de los Ancianos Desamparados sito en el arranque del camino de San Josâ”śÂ®. Sobre el caserâ”śÂˇo de la ciudad de Zaragoza despuntan, como telâ”śâ”‚n de fondo y de izquierda a derecha, la câ”śâ•‘pula de San Ildefonso en el templo dedicado entonces a la advocaciâ”śâ”‚n del Sagrado Corazâ”śâ”‚n, la torre de San Pablo, las câ”śâ•‘pulas y torre del templo del Pilar, la torre y el cimborrio de la Seo, la torre de Santa Marâ”śÂˇa Magdalena y la desmochada torre de San Agustâ”śÂˇn del complejo castrense de las factorâ”śÂˇas militares allâ”śÂˇ ubicadas.', 1900, 1900, 1900, 'Anos 1900', 'TORRERO', 41.63051200, -0.87683500, '0101000020E6100000029F1F46080FECBF27DE019EB4D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54780076645.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54780076645.webp', 'https://www.flickr.com/photos/zaragozaantigua/54780076645/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22155, 'Alto Carabinas 1953', 'Imagen del interior de una infravivienda establecida en la zona de cuevas de Alto Carabinas. En la dâ”śÂ®cada de los aâ”śâ–’os 50, con el inicio del gran "boom" urbano y el denominado "desarrollismo", varias zonas de la periferia de la ciudad se fueron convirtiendo en barriadas donde se instalaron algunos centenares de las familias inmigrantes mâ”śĂ­s empobrecidas llegadas durante el â”śÂ®xodo interior provocado por la extrema miseria y buscando una oportunidad de tener un futuro mâ”śĂ­s digno. Se asentaron en precarios enclaves caracterizados por una tipologâ”śÂˇa de infraviviendas que incluâ”śÂˇa tanto chabolas de superficie, en materiales reciclados de mala calidad constructiva, como cuevas habilitadas en las antiguas graveras, o canteras de extracciâ”śâ”‚n de â”śĂ­ridos, como es el caso. La de la imagen, es una familia de trabajadores proveniente de la provincia de Câ”śâ”‚rdoba, identificada de forma inâ”śÂ®dita para el Gran Archivo Zaragoza Antigua gracias a la amable y fundamental colaboraciâ”śâ”‚n de Cristina Paracuellos Ontiveros.', 1953, 1953, 1953, 'Anos 50', 'TORRERO', 41.62887400, -0.87914300, '0101000020E6100000083C3080F021ECBF01A777F17ED04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29981453610.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29981453610.webp', 'https://www.flickr.com/photos/zaragozaantigua/29981453610/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22330, 'Graveras de La Paz 1960', 'Imagen de la barriada de chabolas instalada en las graveras del barrio de La Paz de Zaragoza. Al fondo, inicio de la construcciâ”śâ”‚n de los grandes bloques de edificios de las Terrazas de Cuâ”śÂ®llar. En primer plano, un equino.', 1960, 1960, 1960, 'Anos 60', 'TORRERO', 41.62887400, -0.87914300, '0101000020E6100000083C3080F021ECBF01A777F17ED04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18646679574.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18646679574.webp', 'https://www.flickr.com/photos/zaragozaantigua/18646679574/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23390, 'Parque Vâ”śÂˇctimas del Terrorismo 2008', 'Dentro de las obras de acompaâ”śâ–’amiento de la Expo 2008, se ejecutâ”śâ”‚ un plan de acondicionamiento de las riberas del Ebro, el Gâ”śĂ­llego, el Huerva y el Canal Imperial de Aragâ”śâ”‚n. A la margen derecha de este â”śâ•‘ltimo curso fluvial pertenece la obra que muestra la foto, en el barrio de La Paz, prolongando el paseo de Tierno Galvâ”śĂ­n con un parque, que serâ”śĂ­ denominado Vâ”śÂˇctimas del Terrorismo. Abajo, la subida al Cabezo Cortado y la margen izquierda del Canal, que en ese largo tramo josefino no fue objeto de acondicionamiento alguno. Fuente visual: Heraldo de Aragâ”śâ”‚n.', 2008, 2008, 2008, 'Siglo XXI', 'TORRERO', 41.63001100, -0.87482000, '0101000020E610000003603C8386FEEBBF658F5033A4D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32557592702.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32557592702.webp', 'https://www.flickr.com/photos/zaragozaantigua/32557592702/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24741, 'Puente del Ferrocarril 1966', 'Imagen de una familia de la comunidad gitana, posando junto a su infravivienda ubicada bajo el puente del ferrocarril tendido entre la Almozara, y la Ortilla, entre los pilares de apoyo de la margen izquierda. Al fondo, un peatâ”śâ”‚n accede por la empinada rampa natural al puente, y se disponde a cruzarlo, si bien el paso era bastante aventurero. A la derecha de la escena se encontraba la piscina de los Baâ”śâ–’os Pâ”śâ•‘blicos, muy frecuentada. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1966, 1966, 1966, 'Anos 60', 'TORRERO', 41.62835400, -0.87922700, '0101000020E61000007E5358A9A022ECBFC82764E76DD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15532855267.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15532855267.webp', 'https://www.flickr.com/photos/zaragozaantigua/15532855267/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25749, 'Canal Imperial 1948', 'Imagen del Canal Imperial en la zona de la curva que conduce al acceso al Cabezo Cortado. La imagen estâ”śĂ­ capturada volviendo desde las esclusas de Valdegurriana, de forma que el Cabezo, y el "Sanatorio de Nuestra Seâ”śâ–’ora del Pilar" para niâ”śâ–’os tuberculosos, quedarâ”śÂˇan a la derecha, ya sobrepasados. Al fondo, una visual de las parcelas de las barriadas de la zona: Colâ”śâ”‚n, ademâ”śĂ­s de la Argentina, y Cuber. A la izquierda, las graveras y terraplenes que caracterizaban esa orilla del Canal, hasta llegar al campo de Torrero, y casi la avenida de Amâ”śÂ®rica. Mientras el objetivo se acerca a la ciudad, varias personas pasean en direcciâ”śâ”‚n contraria, a la derecha, por una estrecha cinta de concreto que aâ”śâ•‘n perdura como espacio por el que deben ir los peatones. Fuente visual: fotografâ”śÂˇa de Mariano Lacruz Berdejo, amablemente aportada por Mariano Lacruz Pâ”śÂ®rez (Archivo Familia Lacruz Pâ”śÂ®rez).', 1948, 1948, 1948, 'Anos 40', 'TORRERO', 41.63072000, -0.87501100, '0101000020E6100000FA7C94111700ECBF7077D66EBBD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20427003085.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20427003085.webp', 'https://www.flickr.com/photos/zaragozaantigua/20427003085/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25770, 'Neptuno 1977', 'Imagen del tramo del antiguo barrio de Colâ”śâ”‚n denominado "Torre-Honda", con primer plano de la calle Neptuno en el punto donde desemboca, a la derecha, la del Tres de Agosto (antigua del 31 de julio), luego redenominada Mohammed Alâ”śÂˇ Amar (vulgo Nanym). Este antiguo entorno parcelario estaba encajonado entre la inmediata fâ”śĂ­brica ALUMALSA (a la derecha, fuera de plano), y los taludes tras los que, al fondo, fluye el Canal Imperial, que podâ”śÂˇa ser cruzado por la pasarela de San Viator. Paralela a esta calle, tras ella, finaliza de forma abrupta la calle Zaragoza la Vieja, de una forma que no puede ser explicada salvo por el impacto del Canal Imperial, cuya construcciâ”śâ”‚n dejâ”śâ”‚ cortado el antiguo camino del Puente del Virrey. Cuarenta aâ”śâ–’os despuâ”śÂ®s, esta zona sigue siendo, mayormente, otro barbecho urbanâ”śÂˇstico a diez minutos del "centro", y uno de los tramos del Canal Imperial que no se sometieron a la intervenciâ”śâ”‚n de embellecimiento con motivo de la Expo 2008. Fuente visual: Banco de Imâ”śĂ­genes/Asociaciâ”śâ”‚n de Vecinos Barrio de San Josâ”śÂ®, amablemente cedida para el', 1977, 1977, 1977, 'Anos 70', 'TORRERO', 41.63090700, -0.87807800, '0101000020E61000006DC9AA083719ECBFA3E8818FC1D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33219076216.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33219076216.webp', 'https://www.flickr.com/photos/zaragozaantigua/33219076216/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25790, 'Calle de Sagunto 1977', 'Invernal imagen capturada en la calle de Sagunto y centrada en la soleada fachada del inmueble nâ”¬â•‘ 19 duplicado de la misma, inmediato al escalonado acceso excavado artesanalmente en el talud de cascajera por donde subir al paseo del Canal. Allâ”śÂˇ destaca un cartel que orienta hacia la piscina de la "Ciudad Deportiva Martâ”śÂˇn Celimâ”śÂ®ndiz" del Arenas S.D. situada a la izquierda, a los pies del Cabezo Cortado. Tras el cartel se cruza el Canal Imperial de Aragâ”śâ”‚n por el puentecillo metâ”śĂ­lico de San Viator que daba nombre a la "calle" que a continuaciâ”śâ”‚n flanqueaba por ese lado las graveras de la Paz. La foto se ha tomado a espaldas de la gran factorâ”śÂˇa de Alumalsa, todavâ”śÂˇa activa desde mediados de los aâ”śâ–’os 40 en esta ubicaciâ”śâ”‚n del antiguo barrio de Colâ”śâ”‚n.', 1977, 1977, 1977, 'Anos 70', 'TORRERO', 41.62999800, -0.87872300, '0101000020E6100000B9C667B27F1EECBFD04543C6A3D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52714330011.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52714330011.webp', 'https://www.flickr.com/photos/zaragozaantigua/52714330011/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25940, 'Andrâ”śÂ® Labarrâ”śÂżre 1986', 'Momento en el que el alcalde socialista de Pau entre 1971 y 2006, Andrâ”śÂ® Labarrâ”śÂżre (1928-2006), inaugura la calle Villa de Pau, hoy rotonda. Estâ”śĂ­ situado en la isleta que reparte el trâ”śĂ­fico rodado de las calles Palma de Mallorca, San Viator y rotonda Villa de Pau. Le flanquean dos emplumados funcionarios del Ayuntamiento de Zaragoza, ciudad hermanada con la de Pau desde 1970. Fuente: AMZ.', 1986, 1986, 1986, 'Anos 80', 'TORRERO', 41.62837900, -0.87766900, '0101000020E610000018D1764CDD15ECBF213F1BB96ED04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15890462606.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15890462606.webp', 'https://www.flickr.com/photos/zaragozaantigua/15890462606/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25952, 'La Paz 1980', 'Imagen capturada en Las Graveras del â”śĂĽrea 37 o zona de chabolas y subviviendas del barrio de La Paz, configurada como uno de los puntos de concentraciâ”śâ”‚n de la marginada poblaciâ”śâ”‚n gitana de la ciudad. Fue desalojado a comienzos de la dâ”śÂ®cada, y sus habitantes reubicados en el poblado de Quinta Julieta. Sobre este degradado entorno de antiguas canteras o cascajeras fue trazado el nuevo parque de La Paz, inaugurado en 1988. Al fondo, modernos bloques en el entorno de la plaza de Gallur. Fuente visual: "Andalâ”śĂ­n, periâ”śâ”‚dico quincenal aragonâ”śÂ®s".', 1980, 1980, 1980, 'Anos 80', 'TORRERO', 41.62887400, -0.87914300, '0101000020E6100000083C3080F021ECBF01A777F17ED04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31880391504.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31880391504.webp', 'https://www.flickr.com/photos/zaragozaantigua/31880391504/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21207, 'Gâ”śâ”‚ndola Pignatelli 1900', '1900. Tal vez la gâ”śâ”‚ndola "Sta. Cecilia" sea la mâ”śĂ­s famosa de las que surcaron el Canal Imperial en el trâ”śĂ­nsito del XIX al XX, por su reconocible y caracterâ”śÂˇstica proa en forma de cisne blanco que, tirada desde la orilla por caballerâ”śÂˇas, llevaba a los viajeros desde la playa de Torrero hasta la Quinta Julieta. La Quinta de Julieta Sagols, arbolada, con cuevas artificiales, dos lagos para remar y una pequeâ”śâ–’a plaza de toros, era un turâ”śÂˇstico destino de la burguesâ”śÂˇa zaragozana del momento, que entonces se conformaba con merendar y pasar una buena tarde de domingo cerca del Cabezo Cortado. No como ahora. Esta barca se guardaba en uno de los diques de Miraflores, tambiâ”śÂ®n en la Playa de Torrero, entre el Puente de Amâ”śÂ®rica y el actual de la prolongaciâ”śâ”‚n de la Avenida S. Josâ”śÂ®. Existieron ademâ”śĂ­s otros barcos que hacâ”śÂˇan ese recorrido canalesco, con interiores aterciopelados y adamascados (en el interior), y sin apenas oleaje (en el exterior), como el "S. Fernando", "Nâ”¬Â¬ Sâ”¬Â¬ del Pilar", "Isabel II", "Sta. Engracia" y "D. Ramâ”śâ”‚n Pignatelli". En la imagen, la gâ”śâ”‚ndola "D. Ramâ”śâ”‚n Pignatelli", arrastrada por un tiro de dos mulos conducido por un arriero, en uno de esos viajes, en este caso, de vuelta. La de la derecha es la ribera del "Camino de Sirga". La navegaciâ”śâ”‚n del Canal fue bastante anterior a la Expo 2008, en que se prometiâ”śâ”‚ recuperarla. Otra promesa incumplida, hasta la fecha. Ahora parece mâ”śĂ­s trascendente el Bronce de Botorrita, del siglo I antes de la Era, que con poner un monumento gratis, ya estâ”śĂ­ la foto garantizada. Sin embargo, hay noches de invierno en que una espectral gâ”śâ”‚ndola parece recorrer el Canal hacia la Quinta Julieta, dejâ”śĂ­ndose llevar por la corriente. Son cosas de la niebla.', 1900, 1900, 1900, 'Anos 1900', 'TORRERO', 41.63011900, -0.88059000, '0101000020E610000092E86514CB2DECBF4BCB48BDA7D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14857887301.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14857887301.webp', 'https://www.flickr.com/photos/zaragozaantigua/14857887301/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24878, 'P.â”¬â•‘ del General Mola 1972', 'Foto Luis Serrano. 1972. En el paseo del General Mola perduraba el impresionante hotelito de Emerenciano Garcâ”śÂˇa, una joya modernista con mayâ”śâ•‘sculas en el nâ”¬â•‘ 54, erigida siguiendo el proyecto firmado en 1909 por Manuel Martâ”śÂˇnez de Ubago, autor tambiâ”śÂ®n del precioso Quiosco de la Mâ”śâ•‘sica levantado para la Exposiciâ”śâ”‚n Hispano-Francesa de 1908. Al igual que la verja del jardâ”śÂˇn, su mirador en el chaflâ”śĂ­n presentaba unas preciosas labores con motivos vegetales de forja y la esquina estaba rematada por un torreâ”śâ”‚n, en origen cubierta por un cupulâ”śÂˇn posteriormente eliminado, aportando una graciosa asimetrâ”śÂˇa a su remate aterrazado, completada por un piâ”śâ–’â”śâ”‚n escalonado de ritmos curvos de ecos gaudinianos, inspirados en obras como la barcelonesa casa Calvet, destacando en la planta noble una ventana bajo un arco parabâ”śâ”‚lico tan caracterâ”śÂˇsticos en la obra de Gaudâ”śÂˇ (a la derecha). Habilitado como Ambulatorio del paseo del General Mola de la Seguridad Social, fue clausurado de esa funciâ”śâ”‚n a finales de 1972 con motivo de la apertura del nuevo Ambulatorio de San Josâ”śÂ®. La casa fue derribada en 1976, a pesar de que se trataba de uno de los mejores y mâ”śĂ­s bellos ejemplos del Modernismo zaragozano. La demoliciâ”śâ”‚n fue comenzada sin licencia municipal y, aunque el Ayuntamiento ordenâ”śâ”‚ su paralizaciâ”śâ”‚n inmediata, finalmente fue derribado, por la polâ”śÂˇtica de los hechos consumados, y levantado lo que hoy podemos contemplar cuando pasamos por esa zona. La imagen muestra tambiâ”śÂ®n el edificio que ocupaba el nâ”¬â•‘ 50, menos vistoso y llamativo, pero que hoy figurarâ”śÂˇa en cualquier guâ”śÂˇa arquitectâ”śâ”‚nica como a preservar. Fue piqueteado, y sustituido por otro mastodonte del montâ”śâ”‚n. Y en medio, el nâ”¬â•‘ 52, abandonado, pero menos intimidado por sus vecinos como pocos aâ”śâ–’os despuâ”śÂ®s, cuando quede emparedado entre bloques de cemento, cristal y postmodernez, hasta que tambiâ”śÂ®n sea piqueteado a finales de los aâ”śâ–’os 90.', 1972, 1972, 1972, 'Anos 70', 'UNIVERSIDAD', 41.64144900, -0.88656100, '0101000020E6100000FD169D2CB55EECBFA58636001BD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14839400996.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14839400996.webp', 'https://www.flickr.com/photos/zaragozaantigua/14839400996/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21500, 'Piscina Iberia F.C. 1926', 'En el verano de 1926, la deportiva "Sociedad Iberia F.C." inaugurâ”śâ”‚ en sus instalaciones de Torrero, junto al Canal Imperial, una piscina "de medidas reglamentarias" para uso y regocijo de la gente asociada. Esta piscina se localizaba junto al terreno de juego de fâ”śâ•‘tbol, que acababa de ser reformado (con campo de hierba, nueva tribuna, y numerosas gradas de cemento). Ademâ”śĂ­s, en lo que hasta hace poco era el campo de entrenamiento de fâ”śâ•‘tbol, se estaba construyendo una pista de carreras ciclistas, para uso de la secciâ”śâ”‚n ciclista de la Sociedad, que pronto sustituirâ”śÂˇa al clausurado "Velâ”śâ”‚dromo Elâ”śÂˇseos". En la imagen, visual de la piscina del Iberia F.C. El campo de fâ”śâ•‘tbol queda a la izquierda, y la nueva pista de ciclismo, a la derecha (inmediata al Canal Imperial). Al fondo, tras los muros, la calle Lasierra Purroy, y mâ”śĂ­s al fondo, la avenida del Puente de Amâ”śÂ®rica al Cementerio (luego, de Amâ”śÂ®rica, a secas) Fuente visual: "Aragâ”śâ”‚n: revista grâ”śĂ­fica de cultura aragonesa" (Aâ”śâ–’o II, Nâ”¬â•‘ 15, diciembre 1926).', 1926, 1926, 1926, 'Anos 20', 'TORRERO', 41.63053100, -0.88306600, '0101000020E610000085B4C6A01342ECBF9D0E643DB5D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15474069709.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15474069709.webp', 'https://www.flickr.com/photos/zaragozaantigua/15474069709/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21511, 'Mausoleo de Costa 1926', 'Extramuros del lâ”śÂˇmite norte (es decir, al sur geogrâ”śĂ­fico) del denominado "Cementerio Viejo" del Cementerio de Torrero, fue erigido en 1914-16 por suscripciâ”śâ”‚n popular este mausoleo al polâ”śÂˇtico, economista, antropâ”śâ”‚logo y referente del Regeneracionismo espaâ”śâ–’ol, Joaquâ”śÂˇn Costa. El busto, obra de Dionisio Lasuâ”śÂ®n, corona una obra coral concebida como una escarpada y râ”śâ•‘stica montaâ”śâ–’a llena de elementos simbâ”śâ”‚licos alusivos a su ideario. En la imagen, Mausoleo con fondo de vales y montes de Torrero. Fuente visual: "Aragâ”śâ”‚n : revista grâ”śĂ­fica de cultura aragonesa" (Aâ”śâ–’o II, Nâ”¬â•‘ 5, febrero 1926).', 1926, 1926, 1926, 'Anos 20', 'TORRERO', 41.62031800, -0.88575000, '0101000020E6100000F2D24D621058ECBF608F899466CF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15661606415.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15661606415.webp', 'https://www.flickr.com/photos/zaragozaantigua/15661606415/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21621, 'Lasierra Purroy 1929', 'Posado de la selecciâ”śâ”‚n absoluta de foot-ball de la repâ”śâ•‘blica de Francia, antes del encuentro amistoso que la enfrentâ”śâ”‚ con la selecciâ”śâ”‚n del reino de Espaâ”śâ–’a en el flamante campo de la Sociedad Iberia F.C, sito en la calle de Lasierra Purroy (Torrero), un luminoso 14 de abril de 1929, dâ”śÂˇa domingo. Parece ser que este fue el primer encuentro internacional de esta disciplina deportiva que tuvo lugar en la ciudad. Tras el seleccionado galo dirigido por Gastâ”śâ”‚n Barreau, la porterâ”śÂˇa de gol sur del campo. Figuran en la imagen: Henrie (portero), Vallet, Bertrant, Paul Nicolas (capitâ”śĂ­n), Dauphin, Bastide, Alex Villaplane, Dutheil, Lieb, Reinante y Galley. El resultado final fue de 8-1 a favor del seleccionado espaâ”śâ–’ol. Alex Villaplane, el jugador de pie a la derecha extrema, con la cabeza agachada, entre 1941 y 1944 fue oficial de la Carlingue o rama francesa de la "Gestapo", colaboracionista con los alemanes ocupantes de su paâ”śÂˇs durante la Segunda Guerra Mundial. Fuente visual: www.todocoleccion.net/', 1929, 1929, 1929, 'Anos 20', 'TORRERO', 41.62984600, -0.88316500, '0101000020E61000005019FF3EE342ECBF1AC231CB9ED04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33374785194.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33374785194.webp', 'https://www.flickr.com/photos/zaragozaantigua/33374785194/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21657, 'Calle de Larraz 1927', 'Imagen capturada en el final del segundo tramo de la arbolada calle de Larraz (actual de Alicante), a espaldas de la homâ”śâ”‚nima y antigua torre que fue pionera en esta perifâ”śÂ®rica zona que a finales del siglo XIX fue comenzada a parcelar como barrio de Venecia. A la izquierda, tramo de los nâ”śâ•‘meros pares de la calle, con construcciones de dos, tres y una altura, incluyendo la enorme torre de Bardavio, esquinera con la calle de Marqueta (actual de Castellâ”śâ”‚n de la Plana). A la derecha, parcelas de una y dos alturas hasta el emboque a las calles de San Marcial y de Almerâ”śÂˇa.', 1927, 1927, 1927, 'Anos 20', 'TORRERO', 41.63179500, -0.88866900, '0101000020E61000003F027FF8F96FECBF5E6397A8DED04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52361851755.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52361851755.webp', 'https://www.flickr.com/photos/zaragozaantigua/52361851755/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21686, 'Câ”śĂ­rcel de Torrero c.1932', 'Abierta en 1928, en 2005 se demoliâ”śâ”‚ parcialmente. Mâ”śĂ­s informaciâ”śâ”‚n: lacalledelamemoria.es/la-carcel-de-torrero/', 1932, 1932, 1932, 'Anos 30', 'TORRERO', 41.62743600, -0.88681700, '0101000020E6100000BA2D910BCE60ECBFA22AA6D24FD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14946131346.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14946131346.webp', 'https://www.flickr.com/photos/zaragozaantigua/14946131346/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21741, 'Velâ”śâ”‚dromo de Torrero 1935', 'Entre el 29 de abril y el 15 de mayo de 1935 tuvo lugar la "1â”¬Â¬ Vuelta Ciclista a Espaâ”śâ–’a", cuya 5â”¬Â¬ etapa se desarrollâ”śâ”‚ entre las ciudades de San Sebastiâ”śĂ­n y Zaragoza, el sâ”śĂ­bado 4 de mayo. En la imagen, y tras nueve horas de pedaleo, celebrada llegada a la lâ”śÂˇnea de meta del ganador de la etapa, Mariano Caâ”śâ–’ardo, en el velâ”śâ”‚dromo de Torrero, inaugurado en 1928 para sustituir al antiguo de los Campos Elâ”śÂˇseos. Esta importante instalaciâ”śâ”‚n deportiva estaba ubicada en la calle de Lasierra Purroy, junto a la piscina y el campo de fâ”śâ•‘tbol donde jugaba el Zaragoza F.C. Al tâ”śÂ®rmino de esta Iâ”¬Â¬ Vuelta Ciclista a Espaâ”śâ–’a, Mariano Caâ”śâ–’ardo quedâ”śâ”‚ en el segundo lugar de la clasificaciâ”śâ”‚n general, por detrâ”śĂ­s del belga Gustaaf Deloor. Fuente visual: A. de la Barrera, Diario As (Madrid).', 1935, 1935, 1935, 'Anos 30', 'TORRERO', 41.63153000, -0.88353000, '0101000020E6100000BD1DE1B4E045ECBFB0389CF9D5D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21816310259.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21816310259.webp', 'https://www.flickr.com/photos/zaragozaantigua/21816310259/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21803, 'Los Alifantes 1935', 'Formaciâ”śâ”‚n del Real Zaragoza Club de Fâ”śâ•‘tbol en la temporada 1934-1935, en la piscina del campo de Torrero. Eran apodados "Los Alifantes". Fuente: Heraldo de Aragâ”śâ”‚n.', 1935, 1935, 1935, 'Anos 30', 'TORRERO', 41.63053100, -0.88306600, '0101000020E610000085B4C6A01342ECBF9D0E643DB5D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26456329417.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26456329417.webp', 'https://www.flickr.com/photos/zaragozaantigua/26456329417/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21968, 'Campo de Torrero 1941', 'Imagen de la inauguraciâ”śâ”‚n oficial del XXIII Campeonato de Espaâ”śâ–’a de "Cross" en el campo de football de Torrero, con presencia en la tribuna de autoridades del general Moscardâ”śâ”‚, ademâ”śĂ­s de otros representantes y jerarcas del Râ”śÂ®gimen, hacia donde se dirigen los saludos, reglamentariamente fascistas, de los atletas, que son correspondidos por los de la asistencia. Hasta el 11-S de 1945, unos dâ”śÂˇas despuâ”śÂ®s de la rendiciâ”śâ”‚n incondicional del Imperio del Japâ”śâ”‚n, este saludo fue obligatorio en todos los actos pâ”śâ•‘blicos del Reino, como este. Al acabar el ceremonial, los 87 participantes del campeonato se encaminaron, corriendo campo traviesa, hacia los cercanos pinares de Venecia. Al fondo, tras el Canal Imperial, silueta del monumental torreâ”śâ”‚n de la antigua Torre de Dâ”śĂ­maso Pina. Fuente: Archivo Celedonio Garcâ”śÂˇa (celedoniogarcia.blogspot.com.es)', 1941, 1941, 1941, 'Anos 40', 'TORRERO', 41.62984600, -0.88316500, '0101000020E61000005019FF3EE342ECBF1AC231CB9ED04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22476267046.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22476267046.webp', 'https://www.flickr.com/photos/zaragozaantigua/22476267046/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22027, 'Cementerio de Torrero 1941', 'Imagen capturada en el cementerio de la "Aviazione Legionaria" fascista italiana de Torrero (inaugurado en 1940 en el homâ”śâ”‚nimo cementerio catâ”śâ”‚lico), cuando la Delegaciâ”śâ”‚n Nacional del Servicio Exterior de Falange, en colaboraciâ”śâ”‚n con la Secciâ”śâ”‚n Femenina del Partido, realizaban un acto simbâ”śâ”‚lico que inauguraba la obra "Madrinas de tumbas de caâ”śÂˇdos italianos", como memorial recuerdo a "la ayuda del Fascismo y la sangre generosamente derramada en nuestros frentes por los combatientes del Imperio italiano". En este caso, la madrina fue ni mâ”śĂ­s ni menos que Pilar Primo de Rivera, Delegada nacional de la Secciâ”śâ”‚n Femenina que asistiâ”śâ”‚ a la ceremonia y asumiâ”śâ”‚ el cuidado y embellecimiento de la tumba de Pietro Barresi, considerado primer "caâ”śÂˇdo" italiano en tierra aragonesa, si bien posteriormente se situâ”śâ”‚ su muerte en Esquivias (Toledo). La ceremonia contâ”śâ”‚ con la asistencia de los altos mandos militares de la regiâ”śâ”‚n, autoridades civiles y militares de la provincia, el Ayuntamiento y los representantes de los embajadores de Italia y Alemania. Durante la preceptiva misa se colocaron coronas ofrecidas por Falange, Aviaciâ”śâ”‚n y el Fascio Italiano de Zaragoza ante el supuesto sepulcro de Barresi. Ximâ”śÂ®nez de Sandoval, jefe del Gabinete Diplomâ”śĂ­tico del Ministro de Asuntos Exteriores, pronunciâ”śâ”‚ un vibrante monâ”śâ”‚logo donde no faltaron referencias a la Virgen del Pilar. Cerrâ”śâ”‚ el acto el canto, brazo en alto, del himno fascista y del Cara al Sol a los acordes de las bandas militares, y un postrero desfile.', 1941, 1941, 1941, 'Anos 40', 'TORRERO', 41.62338200, -0.88386200, '0101000020E61000003BAB05F69848ECBF21753BFBCACF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50388822032.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50388822032.webp', 'https://www.flickr.com/photos/zaragozaantigua/50388822032/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22040, 'Paseo del Canal c.1954', 'Imagen del Canal Imperial de Aragâ”śâ”‚n capturada en el tramo de la gran curva que traza en las terrazas de Pina, donde deriva agua a travâ”śÂ®s de la acequia de Ontonar, que poco mâ”śĂ­s adelante surte a la fâ”śĂ­brica textil de Pina. Al fondo, edificios del Canal Imperial inmediatos al cuartel de Torrero (a la izquierda, fuera de plano). A la derecha, la antigua gran torre del nâ”¬â•‘ 340 del paseo, que todavâ”śÂˇa supervive, abandonada y en barbecho urbanâ”śÂˇstico, como nâ”¬â•‘ 23-25. Junto a ella, transita un prâ”śÂˇstino Seat 1400. Como sucede con regular periodicidad, el Canal baja sin agua para acometer tareas de limpieza y mantenimiento. En la zona del estrechamiento y salto de agua canalino, tiempo despuâ”śÂ®s se colocarâ”śÂˇa una pasarela peatonal de paso Fuente visual: archivo Heraldo de Aragâ”śâ”‚n, en "Padre Ebro. El râ”śÂˇo Ebro y el siglo XX".', 1954, 1954, 1954, 'Anos 50', 'TORRERO', 41.63225400, -0.88158700, '0101000020E61000002385B2F0F535ECBFF261F6B2EDD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14740164988.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14740164988.webp', 'https://www.flickr.com/photos/zaragozaantigua/14740164988/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22051, 'Canal Imperial 1956', 'Foto: Josâ”śÂ® Antonio Duce. Invierno de 1956. El Canal Imperial de Aragâ”śâ”‚n, helado.', 1956, 1956, 1956, 'Anos 50', 'TORRERO', 41.63034300, -0.89211300, '0101000020E61000002FC4EA8F308CECBF9B215514AFD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14894292836.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14894292836.webp', 'https://www.flickr.com/photos/zaragozaantigua/14894292836/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22173, 'Barrio de Nâ”¬Â¬ Sâ”¬Â¬ 1954', 'Dibujo publicitario con que se ilustraba el proyecto del "Nuevo Barrio de Nuestra Seâ”śâ–’ora", autoproclamado como "La soluciâ”śâ”‚n verdad al problema de la vivienda". 1200 pisos proyectados a la â”śâ•‘ltima, en cuanto a equipamientos, lo convertâ”śÂˇan en "el barrio mâ”śĂ­s moderno de Zaragoza", y los comerciales insertos en prensa ya introducâ”śÂˇan la coletilla "a diez minutos de la plaza de Espaâ”śâ–’a" (en tranvâ”śÂˇa, lâ”śÂˇnea 5 "Venecia-Delicias"). Ubicado entre el Campo de Deportes de Torrero (al fondo) y el Canal Imperial (en primer plano), junto a la calle Lasierra Purroy (derecha), este desarrollo urbanâ”śÂˇstico aparece imaginativamente desarrollado en el dibujo, incluyendo torres de 15-16 alturas, nuevos puentes sobre el Canal, y amplios nuevos viales sospechosamente sin circulaciâ”śâ”‚n rodada. La realizaciâ”śâ”‚n prâ”śĂ­ctica dejarâ”śĂ­ las torres a mitad de altura, una densidad edilicia bastante menor, y los puentes y nuevas avenidas en modo espera, por unas cuantas dâ”śÂ®cadas. A veces, la realidad no se ajusta a la publicidad de las promotoras. Fuente visual: diario "El Noticiero". Archivo Josâ”śÂ® Marâ”śÂˇa Ballestâ”śÂˇn Miguel.', 1954, 1954, 1954, 'Anos 50', 'TORRERO', 41.63129200, -0.88366800, '0101000020E6100000FFB1101D0247ECBFFC1C1F2DCED04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31475502252.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31475502252.webp', 'https://www.flickr.com/photos/zaragozaantigua/31475502252/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22303, 'Misa en Torrero 1968', 'Archivo Municipal. Gerardo Sancho Ramo. 1968. "Misa en la câ”śĂ­rcel de Torrero." Han pasado 28 aâ”śâ–’os y estamos en el mismo escenario, pero ni siquiera el guiâ”śâ”‚n es ya el mismo. Ha llovido tanto acero, tanta sangre, que la tierra estâ”śĂ­ empapada, y ya no es necesaria la parafernalia de antaâ”śâ–’o. El retrato del conductor, del guâ”śÂˇa, del lâ”śÂˇder, anda en algâ”śâ•‘n desvâ”śĂ­n cogiendo polvo. Los "vivas" ya no son necesarios para garantizar la longevidad del râ”śÂ®gimen. El exceso de metros cuadrados de banderas nacionalistas ya sâ”śâ”‚lo se saca cuando el contubernio actâ”śâ•‘a, y hay que marcar territorio. Los saludos fascistas incomodan a la tecnocracia que se aferra con esperanza al prâ”śÂˇncipe para que todo siga igual. Ya no hay tantos inquilinos como antaâ”śâ–’o, y las ropas, los cortes de pelo, la estâ”śÂ®tica, se ha relajado en las formas. Ha pasado mucho tiempo, pero todos saben perfectamente lo que ha pasado, y lo que no va a pasar. En la imagen, misa en el interior de la câ”śĂ­rcel de Torrero, como podâ”śÂˇa serlo en una parroquia catâ”śâ”‚lica al uso, de la â”śÂ®poca. Pero sâ”śâ”‚lo para malos hombres.', 1968, 1968, 1968, 'Anos 60', 'TORRERO', 41.62731500, -0.88698400, '0101000020E6100000906802452C62ECBF27A5A0DB4BD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15613426538.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15613426538.webp', 'https://www.flickr.com/photos/zaragozaantigua/15613426538/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22487, 'RNE 1968', 'Aâ”śÂ®rea visual centrada, en primer tâ”śÂ®rmino, en las novâ”śÂˇsimas instalaciones (inauguradas oficialmente el 18 de julio de ese aâ”śâ–’o) del centro emisor y estudios de Radio Nacional de Espaâ”śâ–’a en Zaragoza. La vista incluye una interesante panorâ”śĂ­mica de la zona sur del barrio de Venecia, entre el antiguo camino de Cuarte y los pinares de Venecia, a la izquierda, y el cementerio catâ”śâ”‚lico de Torrero, en el extremo inferior derecho, incluyendo en ella, entre otros elementos urbanos, el Grupo de Viviendas Hogar Cristiano, la terrosa calle de Fray Juliâ”śĂ­n Garcâ”śÂ®s (antiguo camino de las Canteras), el Centro Penitenciario de Detenciâ”śâ”‚n o Prisiâ”śâ”‚n Provincial de Zaragoza, el moderno colegio Domingo Miral, los depâ”śâ”‚sitos de aguas de Las Canteras (construidos en el inicio de los aâ”śâ–’os treinta), y la enorme extensiâ”śâ”‚n recreativa del reciente Stadium Venecia. Al fondo, descendiendo las sucesivas terrazas, la ciudad de Zaragoza. Fuente visual: exposiciâ”śâ”‚n Ă”Ă‡Ă–50 aâ”śâ–’os RNE Aragâ”śâ”‚nĂ”Ă‡Ă–.', 1968, 1968, 1968, 'Anos 60', 'TORRERO', 41.62358500, -0.89040600, '0101000020E61000008C3045B9347EECBF59A31EA2D1CF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/43033376230.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/43033376230.webp', 'https://www.flickr.com/photos/zaragozaantigua/43033376230/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22526, 'Campo de Torrero 1975', 'A la izquierda de la avenida de Amâ”śÂ®rica, ribera derecha del Canal donde el Puente de Amâ”śÂ®rica, justo despuâ”śÂ®s de las instalaciones de la Confederaciâ”śâ”‚n Hidrogrâ”śĂ­fica del Ebro y de las primeras parcelitas, habâ”śÂˇa un terreno la verdad es que muy poco propicio. Las acusadas irregularidades y la pobre composiciâ”śâ”‚n del suelo (derrubios y gravas acumuladas), hacâ”śÂˇan que apenas si agarraran unos pocos y sufridos terrenos de viâ”śâ–’edo. Mejor se daban los abejares, y mucho mâ”śĂ­s los "eriales" y las caracterâ”śÂˇsticas "graveras" (lugar de extracciâ”śâ”‚n de gravas) de la zona. La calle Lasierra Purroy marcaba el fin del incipiente barrio de Torrero, cuando en esta zona se construyâ”śâ”‚ un velâ”śâ”‚dromo que venâ”śÂˇa a sustituir al que hasta entonces existâ”śÂˇa donde el actual cine Elâ”śÂˇseos. Se excavâ”śâ”‚ a su lado, ademâ”śĂ­s, una gran piscina, y en 1923 el "Iberia Sport Club" levantâ”śâ”‚ un nuevo campo de fâ”śâ•‘tbol, que serâ”śĂ­ el campo del Real Zaragoza de 1932 a 1957. Con la mudanza al nuevo y municipal campo allâ”śĂ­ donde la acequia de la Romareda, el campo de Torrero fue decayendo hasta que a finales de los 80 del siglo pasado fue derruido, y la zona comenzâ”śâ”‚ a ser urbanizada y reordenada con nuevos bloques de viviendas ademâ”śĂ­s de, ya en 1998, el Centro Câ”śÂˇvico "Torrero". En la imagen, captura de los restos del campo de Torrero desde la ribera del Canal. Mâ”śĂ­s allâ”śĂ­ del Canal se perciben claramente las irregularidades del terreno, y el comienzo de la zona de las graveras. La destacable grada de cemento, de 10 metros de altura, habâ”śÂˇa sido aâ”śâ–’adida como ampliaciâ”śâ”‚n de aforo en 1943. Los bloques de viviendas de la derecha, terminados en el aâ”śâ–’o 1976, se corresponden con los nâ”śâ•‘meros 6, 8, 10, 12 y 14 de la calle de Honorio Garcâ”śÂˇa Condoy, abierta ese mismo aâ”śâ–’o. Una vez derribado el campo de Torrero, justo donde termina el bloque central se abrirâ”śĂ­ la nueva calle Doctor Pascual Oliver, y poco a poco se empezarâ”śĂ­n a levantar bloques de viviendas sobre el solar: el nâ”¬â•‘ 2 en 1987, el nâ”¬â•‘ 4 en 1989, el nâ”¬â•‘ 6 en 2000, y el nâ”¬â•‘ 8 en 2001. Lo mismo suced', 1975, 1975, 1975, 'Anos 70', 'TORRERO', 41.63115300, -0.88113200, '0101000020E6100000B8B06EBC3B32ECBFDAE21A9FC9D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14669307568.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14669307568.webp', 'https://www.flickr.com/photos/zaragozaantigua/14669307568/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22588, 'Câ”śĂ­rcel de Torrero 1977', 'Imagen de la cara sur de la câ”śĂ­rcel provincial de Torrero, desde la Avenida de Amâ”śÂ®rica. Los bloques de vivienda del fondo, del casi final de la calle Fray Juliâ”śĂ­n Garcâ”śÂ®s. Es visible una de las torrecillas de vigilancia situadas en las esquinas del complejo carcelario, y dos guardianes. La entrada por la Avenida de Amâ”śÂ®rica queda fuera de plano, a la derecha. Esta câ”śĂ­rcel fue construida en 1928, y desmantelada parcialmente en 2005.', 1977, 1977, 1977, 'Anos 70', 'TORRERO', 41.62741600, -0.88738200, '0101000020E6100000EBE3A1EF6E65ECBF5A7EE02A4FD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15727426296.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15727426296.webp', 'https://www.flickr.com/photos/zaragozaantigua/15727426296/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22608, 'Calle Cuarte 1971', 'La calle de Cuarte en el barrio de Venecia, desde la altura del nâ”¬â•‘ 2 de la calle de Loarre. A la izquierda y en primer tâ”śÂ®rmino, aspecto del moderno colegio El â”śĂĽngel de la Guarda, inaugurado en 1968 sobre la parcela que desde desde 1955 se ofrecâ”śÂˇan clases particulares a niâ”śâ–’os pequeâ”śâ–’os, y que en 1958 se abriâ”śâ”‚ ya como colegio en la esquina con la calle del Pinar, que linda con los Pinares de Venecia. A la derecha, inmueble esquinero del nâ”¬â•‘ 52 de la calle del Parque, luego derribado y sustituido por otro nuevo. Al fondo a la izquierda, las torres del Pilar. En el centro, la del Sacrario Militare Italiano.', 1971, 1971, 1971, 'Anos 70', 'TORRERO', 41.62973300, -0.89064400, '0101000020E6100000B01D8CD82780ECBF221B48179BD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19088636666.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19088636666.webp', 'https://www.flickr.com/photos/zaragozaantigua/19088636666/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
